def is_expired(path: Path, category: str, config: dict):
    """Determine if file is expired based on category and config."""
    age = get_file_age_days(path)
    if category == "TEMPORARY":
        return age > config["expiration_days_temporary"]
    elif category == "PROJECT_ARTIFACT":
        return age > config["expiration_days_project_artifact"]
    elif category == "SYSTEM" or category == "SAFE":
        return False
    else:  # UNKNOWN
        return False  # never auto-expire

