#!/usr/bin/env python3
"""
Simple test to verify environment variable loading works
"""

import os
import sys

# Simple .env file loader
def load_env_file(env_path):
    """Load environment variables from .env file."""
    try:
        with open(env_path, 'r') as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith('#'):
                    continue
                if '=' in line:
                    key, value = line.split('=', 1)
                    os.environ[key.strip()] = value.strip()
                    print(f"Loaded: {key.strip()}=[REDACTED]")
        return True
    except Exception as e:
        print(f"Error loading .env file: {e}")
        return False

# Test loading
env_path = os.path.expanduser("~/.openclaw/.env")
print(f"Loading .env from: {env_path}")

if os.path.exists(env_path):
    load_env_file(env_path)

    # Check if variables are loaded
    required_vars = ["TAVILY_API_KEY", "DEEPSEEK_API_KEY", "GEMINI_API_KEY"]

    print("\nChecking environment variables:")
    for var in required_vars:
        value = os.environ.get(var)
        if value:
            print(f"✅ {var}: Set (length: {len(value)})")
        else:
            print(f"❌ {var}: Not set")
else:
    print(f"❌ .env file not found at {env_path}")

# Test variable substitution
print("\nTesting variable substitution in config files:")
test_config = {
    "api_key": "${TAVILY_API_KEY}",
    "deepseek_key": "${DEEPSEEK_API_KEY}",
    "missing": "${MISSING_VAR}"
}

for key, value in test_config.items():
    if value.startswith("${") and value.endswith("}"):
        var_name = value[2:-1]
        env_value = os.environ.get(var_name)
        if env_value:
            print(f"✅ {key}: Variable {var_name} resolved from env")
        else:
            print(f"❌ {key}: Variable {var_name} not found in env")

